package xy.onlasdan.galery.crypto

import android.content.Context
import ca.pkay.rcloneexplorer.RcloneRcd
import java.io.File

/**
 * Wraps RcloneRcd to upload/download/list/delete files via a rclone crypt remote.
 *
 * Requires a rclone.conf with a crypt remote named "galery" configured.
 * The conf is generated by [setupRcloneConf] using keys from [CryptKeyStore].
 */
class RcloneCryptProvider(private val context: Context) {

    private val rcd = RcloneRcd()

    fun setupRcloneConf() {
        val keys = CryptKeyStore(context)
        if (!keys.isConfigured()) return
        val conf = """
            [galery]
            type = crypt
            password = ${keys.password()}
            salt = ${keys.salt()}
        """.trimIndent()
        val confFile = File(context.filesDir, "rclone.conf")
        confFile.writeText(conf)
        // TODO: point RcloneRcd at this conf path
    }

    suspend fun upload(localPath: File, remotePath: String): Boolean {
        // TODO: call rclone copy via RcloneRcd
        return rcd.rcloneCopy(localPath.absolutePath, "galery:$remotePath")
    }

    suspend fun download(remotePath: String, localPath: File): Boolean {
        return rcd.rcloneCopy("galery:$remotePath", localPath.absolutePath)
    }

    suspend fun list(remotePath: String): List<String> {
        return rcd.rcloneLsd("galery:$remotePath")
    }

    suspend fun delete(remotePath: String): Boolean {
        return rcd.rcloneDeleteFile("galery:$remotePath")
    }
}
